  `done_by_y` tinyint(1) NOT NULL,
  `completed_at_x` datetime(6) DEFAULT NULL,
  `completed_at_y` datetime(6) DEFAULT NULL,
  `duration_minutes_x` int DEFAULT NULL,
  `duration_minutes_y` int DEFAULT NULL,
  `cancellation_reason` longtext,
  `created_at` datetime(6) NOT NULL,
  `updated_at` datetime(6) NOT NULL,
  `initiated_by_id` char(32) DEFAULT NULL,
  `user_x_id` char(32) NOT NULL,
  `user_y_id` char(32) NOT NULL,
  `exchange_request_id` bigint DEFAULT NULL,
  `skill_from_x_to_y_id` bigint NOT NULL,
  `skill_from_y_to_x_id` bigint NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uuid` (`uuid`),
  UNIQUE KEY `exchanges_exchange_request_id_init_140a437a_uniq` (`exchange_request_id`,`initiated_by_id`,`status`),
  KEY `exchanges_skill_from_x_to_y_id_b9ce0865_fk_skills_id` (`skill_from_x_to_y_id`),
  KEY `exchanges_skill_from_y_to_x_id_b24aa7b1_fk_skills_id` (`skill_from_y_to_x_id`),
  KEY `exchanges_initiated_by_id_623875b9_fk_users_id` (`initiated_by_id`),
  KEY `exchanges_user_x_id_62ca1a87_fk_users_id` (`user_x_id`),
  KEY `exchanges_user_y_id_1c1c4da5_fk_users_id` (`user_y_id`),
  CONSTRAINT `exchanges_exchange_request_id_1ffee9b6_fk_exchange_requests_id` FOREIGN KEY (`exchange_request_id`) REFERENCES `exchange_requests` (`id`),
  CONSTRAINT `exchanges_initiated_by_id_623875b9_fk_users_id` FOREIGN KEY (`initiated_by_id`) REFERENCES `users` (`id`),
  CONSTRAINT `exchanges_skill_from_x_to_y_id_b9ce0865_fk_skills_id` FOREIGN KEY (`skill_from_x_to_y_id`) REFERENCES `skills` (`id`),
  CONSTRAINT `exchanges_skill_from_y_to_x_id_b24aa7b1_fk_skills_id` FOREIGN KEY (`skill_from_y_to_x_id`) REFERENCES `skills` (`id`),
  CONSTRAINT `exchanges_user_x_id_62ca1a87_fk_users_id` FOREIGN KEY (`user_x_id`) REFERENCES `users` (`id`),
  CONSTRAINT `exchanges_user_y_id_1c1c4da5_fk_users_id` FOREIGN KEY (`user_y_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=22 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
